INSERT INTO `yl_guide` VALUES (25, '上海交通大学心理学院（含精神卫生中心2026年硕士招生专业目录', '<h1>上海交通大学心理学院（含精神卫生中心2026年硕士招生专业目录</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/52.shtml\" target=\"_blank\" title=\"更多专业目录相关内容列表\">专业目录</a> 来源：上海交通大学研究生招生网 2025-12-11　 相关院校：<a href=\"/graduate/grad/schoolID/4.shtml\" title=\"上海交通大学研究生院\" target=\"_blank\"><b>上海交通大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/4.shtml\" target=\"_blank\" title=\"上海交通大学考研资料\"><font color=\"#ff0000\">上海交通大学2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>从上海交通大学研究生招生网获悉，上海交通大学2026年硕士研究生招生专业目录已发布，如下：</p>\n <table border=\"1\" width=\"98%\">\n  <tbody>\n   <tr>\n    <td><strong>院系代码名称</strong></td>\n    <td><strong>招生计划</strong></td>\n    <td><strong>专业代码名称</strong></td>\n    <td><strong>学位类型</strong></td>\n    <td><strong>研究方向</strong></td>\n    <td><strong>学习方式</strong></td>\n    <td><strong>考试科目</strong></td>\n    <td><strong>备注</strong></td>\n   </tr>\n   <tr>\n    <td rowspan=\"3\">541心理学院（含精神卫生中心）</td>\n    <td rowspan=\"3\">总招生计划：115，全日制学术学位15，全日制专业学位20，非全日制专业学位80。 其中全日制推免生招生计划20</td>\n    <td>040200心理学</td>\n    <td>学术学位</td>\n    <td>01不区分方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②201英语（一）③312心理学专业基础④--无</td>\n    <td>&nbsp;</td>\n   </tr>\n   <tr>\n    <td rowspan=\"2\">045400应用心理</td>\n    <td rowspan=\"2\">专业学位</td>\n    <td>01不区分方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②204英语（二）③347心理学专业综合④--无</td>\n    <td>&nbsp;</td>\n   </tr>\n   <tr>\n    <td>02不区分方向，在职学习。</td>\n    <td>(2)非全日制</td>\n    <td>①101思想政治理论②204英语（二）③347心理学专业综合④--无</td>\n    <td>&nbsp;</td>\n   </tr>\n  </tbody>\n </table>\n <p>&nbsp;</p>\n</div>', 'zhuanyemulu', NULL, 0, 1, '2025-12-12 15:04:38', NULL, 0, '上海交通大学', '不限', 0);
