INSERT INTO `yl_guide` VALUES (30, '上海交通大学设计学院2026年硕士招生专业目录', '<h1>上海交通大学设计学院2026年硕士招生专业目录</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/52.shtml\" target=\"_blank\" title=\"更多专业目录相关内容列表\">专业目录</a> 来源：上海交通大学研究生招生网 2025-12-11　 相关院校：<a href=\"/graduate/grad/schoolID/4.shtml\" title=\"上海交通大学研究生院\" target=\"_blank\"><b>上海交通大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/4.shtml\" target=\"_blank\" title=\"上海交通大学考研资料\"><font color=\"#ff0000\">上海交通大学2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>从上海交通大学研究生招生网获悉，上海交通大学2026年硕士研究生招生专业目录已发布，如下：</p>\n <table border=\"1\" width=\"98%\">\n  <tbody>\n   <tr>\n    <td><strong>院系代码名称</strong></td>\n    <td><strong>招生计划</strong></td>\n    <td><strong>专业代码名称</strong></td>\n    <td><strong>学位类型</strong></td>\n    <td><strong>研究方向</strong></td>\n    <td><strong>学习方式</strong></td>\n    <td><strong>考试科目</strong></td>\n    <td><strong>备注</strong></td>\n   </tr>\n   <tr>\n    <td rowspan=\"7\">430设计学院</td>\n    <td rowspan=\"7\">总招生计划：108，全日制学术学位18，全日制专业学位90。 其中全日制推免生招生计划52</td>\n    <td rowspan=\"2\">081300建筑学</td>\n    <td rowspan=\"2\">学术学位</td>\n    <td>01建筑设计及其理论、建筑历史与理论及历史建筑保护、城市设计及其理论</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>建筑学、环境艺术、城市规划、风景园林、城市设计、建筑环境与能源应用工程、能源工程类、土木工程等相关专业均可报考，可以跨学科报考的专业：经济学、管理学、社会学、历史学、博物馆学、机械工程。</td>\n   </tr>\n   <tr>\n    <td>02建筑技术科学</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>建筑学、环境艺术、城市规划、风景园林、城市设计、建筑环境与能源应用工程、能源工程类、土木工程等相关专业均可报考，可以跨学科报考的专业：经济学、管理学、社会学、历史学、博物馆学、机械工程。</td>\n   </tr>\n   <tr>\n    <td>085100建筑</td>\n    <td>专业学位</td>\n    <td>01不区分研究方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②201英语（一）③355建筑学基础④911建筑设计</td>\n    <td>报考本专业考生须到上海交通大学考点参加考试，报考点必须为上海交通大学。建筑学、城市规划、历史建筑保护工程、城市设计、风景园林、环境艺术等相关专业均可报考，可以跨学科报考的专业：土木工程。</td>\n   </tr>\n   <tr>\n    <td>085500机械</td>\n    <td>专业学位</td>\n    <td>01不区分研究方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②201英语（一）③337工业设计工程④887工业设计工程专业基础</td>\n    <td>报考本专业考生须到上海交通大学考点参加考试，报考点必须为上海交通大学。考试时需带马克笔、彩色铅笔、色粉笔、尺规等设计用绘图工具。</td>\n   </tr>\n   <tr>\n    <td>086200风景园林</td>\n    <td>专业学位</td>\n    <td>01不区分研究方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②201英语（一）③344风景园林基础④913风景园林设计与植物应用</td>\n    <td>报考本专业考生须到上海交通大学考点参加考试，报考点必须为上海交通大学。可跨学科报考的专业：建筑类、环艺类、林学类、生物科学类、农学学科相关专业；复试时需进行“风景园林专业知识综合（含快题设计）”。</td>\n   </tr>\n   <tr>\n    <td>135700设计</td>\n    <td>专业学位</td>\n    <td>01不区分研究方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②201英语（一）③336艺术基础④914艺术设计</td>\n    <td>报考本专业考生须到上海交通大学考点参加考试，报考点必须为上海交通大学。本专业不指定考试科目的参考书和参考材料，不划定考试内容范围等；面试分笔试和口试两部分，笔试部分主要考察综合知识，口试部分主要考察考生从事本专业的基本素质。</td>\n   </tr>\n   <tr>\n    <td>140300设计学</td>\n    <td>学术学位</td>\n    <td>01不区分研究方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②201英语（一）③336艺术基础④914艺术设计</td>\n    <td>报考本专业考生须到上海交通大学考点参加考试，报考点必须为上海交通大学。本专业不指定考试科目的参考书和参考材料，不划定考试内容范围等；面试分笔试和口试两部分，笔试部分主要考察综合知识，口试部分主要考察考生从事本专业的基本素质。</td>\n   </tr>\n  </tbody>\n </table>\n</div>', 'zhuanyemulu', NULL, 1, 1, '2025-12-12 15:04:42', NULL, 0, '上海交通大学', '不限', 0);
