INSERT INTO `yl_guide` VALUES (34, '上海交通大学教育学院2026年硕士招生专业目录', '<h1>上海交通大学教育学院2026年硕士招生专业目录</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/52.shtml\" target=\"_blank\" title=\"更多专业目录相关内容列表\">专业目录</a> 来源：上海交通大学研究生招生网 2025-12-11　 相关院校：<a href=\"/graduate/grad/schoolID/4.shtml\" title=\"上海交通大学研究生院\" target=\"_blank\"><b>上海交通大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/4.shtml\" target=\"_blank\" title=\"上海交通大学考研资料\"><font color=\"#ff0000\">上海交通大学2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>从上海交通大学研究生招生网获悉，上海交通大学2026年硕士研究生招生专业目录已发布，如下：</p>\n <table border=\"1\" width=\"98%\">\n  <tbody>\n   <tr>\n    <td><strong>院系代码名称</strong></td>\n    <td><strong>招生计划</strong></td>\n    <td><strong>专业代码名称</strong></td>\n    <td><strong>学位类型</strong></td>\n    <td><strong>研究方向</strong></td>\n    <td><strong>学习方式</strong></td>\n    <td><strong>考试科目</strong></td>\n    <td><strong>备注</strong></td>\n   </tr>\n   <tr>\n    <td rowspan=\"8\">350教育学院</td>\n    <td rowspan=\"8\">总招生计划：61，全日制学术学位12，全日制专业学位49。 其中全日制推免生招生计划52</td>\n    <td>040100教育学</td>\n    <td>学术学位</td>\n    <td>01不分研究方向</td>\n    <td>(1)全日制</td>\n    <td>①101思想政治理论②201英语（一）③311教育学专业基础④--无</td>\n    <td>统考招收9名学生</td>\n   </tr>\n   <tr>\n    <td>045103学科教学（语文）</td>\n    <td>专业学位</td>\n    <td>01仅面向推免生选拔，不从全国研究生统一考试中选拔。</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>文史类相关专业可以跨专业报考</td>\n   </tr>\n   <tr>\n    <td>045104学科教学（数学）</td>\n    <td>专业学位</td>\n    <td>01仅面向推免生选拔，不从全国研究生统一考试中选拔。</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>理工科各专业均可以跨专业报考</td>\n   </tr>\n   <tr>\n    <td>045105学科教学（物理）</td>\n    <td>专业学位</td>\n    <td>01仅面向推免生选拔，不从全国研究生统一考试中选拔。</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>理工科各专业均可以跨专业报考</td>\n   </tr>\n   <tr>\n    <td>045106学科教学（化学）</td>\n    <td>专业学位</td>\n    <td>01仅面向推免生选拔，不从全国研究生统一考试中选拔。</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>理工科各专业均可以跨专业报考</td>\n   </tr>\n   <tr>\n    <td>045107学科教学（生物）</td>\n    <td>专业学位</td>\n    <td>01仅面向推免生选拔，不从全国研究生统一考试中选拔。</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>仅招收生、农、医、药等相关专业</td>\n   </tr>\n   <tr>\n    <td>045108学科教学（英语）</td>\n    <td>专业学位</td>\n    <td>01仅面向推免生选拔，不从全国研究生统一考试中选拔。</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>仅招收外语类相关专业报考</td>\n   </tr>\n   <tr>\n    <td>045117科学与技术教育</td>\n    <td>专业学位</td>\n    <td>01仅面向推免生选拔，不从全国研究生统一考试中选拔。</td>\n    <td>(1)全日制</td>\n    <td>仅推免生选拔</td>\n    <td>理工科各专业均可以跨专业报考</td>\n   </tr>\n  </tbody>\n </table>\n</div>', 'zhuanyemulu', NULL, 0, 1, '2025-12-12 15:04:44', NULL, 0, '上海交通大学', '不限', 0);
INSERT INTO `yl_guide` VALUES (35, '准备就绪！教育部提醒广大研考考生诚信考试', '<h1>准备就绪！教育部提醒广大研考考生诚信考试</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：微言教育 2024-12-20　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>2025年全国硕士研究生招生考试将于2024年12月21日至22日举行。教育部深入贯彻落实习近平总书记等中央领导同志重要指示精神，树牢底线思维、极限思维，会同中央宣传部、中央网信办、中央保密办、工业和信息化部、公安部等国家教育统一考试工作部际联席会议成员单位，召开研考安全工作视频会议、印发专项工作文件，进行全面动员部署，联合开展综合治理考试环境专项行动，严守考试安全、公平底线；严肃考风考纪，强化人防、物防、技防相结合，大力推动考场综合安防体系建设；加强协调调度，指导各地全面排查整治考试组织安全隐患和薄弱环节、完善应急预案、优化考生服务，全力实现平安研考。各省（区、市）党委政府高度重视研考组织工作，加强组织领导，周密部署检查；教育部门积极会同各有关部门齐抓共管、协调联动，强化安全责任落实。目前，全国研考各项工作准备就绪。</p>\n <p>全国硕士研究生招生考试是法律规定国家考试，凡在考试中作弊的考生，其作弊事实将依法记入《国家教育考试考生诚信档案》，并通报其所在学校或单位。广大考生应知法守法，严格遵守考试考场规则，切实履行诚信考试义务，以诚取信，以信取胜，莫拿个人诚信当儿戏。遵守考试纪律，不携带手机等违禁物品进入考场，不心存侥幸替他人或者让他人代替自己参加考试，不参与涉考违法犯罪活动；服从监考人员管理，主动接受身份核验和考试违禁物品检查。</p>\n <p><strong>教育部提醒广大考生&#x2014;&#x2014;</strong></p>\n <p>及时关注天气变化，注意防寒保暖，做好个人健康防护；</p>\n <p>提前认真阅读考试须知，认真核实确认考试时间、地点，仔细检查考试所须携带的证件和文具，合理规划赴考行程安排；</p>\n <p>保持积极心态和良好身体状态，沉着冷静参加考试。</p>\n</div>', 'zhaoshengjianzhang', NULL, 0, 1, '2025-12-12 15:06:15', NULL, 0, '未知院校', '不限', 0);
INSERT INTO `yl_guide` VALUES (36, '2025年全国硕士研究生招生考试（初试）温馨提示汇总', '<h1>2025年全国硕士研究生招生考试（初试）温馨提示汇总</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/9.shtml\" target=\"_blank\" title=\"更多研招新闻相关内容列表\">研招新闻</a> 来源：研招网 2024-12-14　\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/.shtml\" target=\"_blank\" title=\"考研资料\"><font color=\"#ff0000\">2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p><strong>注：信息不断添加中，以下通知如有变动，以省招办公布的最新信息为准。</strong></p>\n <table width=\"98%\" align=\"center\" border=\"1\" cellspacing=\"1\" cellpadding=\"1\">\n  <tbody>\n   <tr>\n    <th>省市</th>\n    <th>温馨提示</th>\n   </tr>\n   <tr>\n    <td>北京</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241209/2293348406.html\">北京市2025年全国硕士研究生招生考试（初试）考生须知</a></td>\n   </tr>\n   <tr>\n    <td>天津</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241213/2293348652.html\">天津：研途护航 | 考前温馨提示之考试安排</a></td>\n   </tr>\n   <tr>\n    <td>河北</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241213/2293349957.html\">河北省2025年全国硕士研究生招生考试（初试）考场规则及注意事项</a><br>\n      &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241211/2293348537.html\">河北省2025年全国硕士研究生招生考试各地信息发布网站、公众号、咨询电话和邮箱信息汇总</a></td>\n   </tr>\n   <tr>\n    <td>山西</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241213/2293349941.html\"></a></td>\n   </tr>\n   <tr>\n    <td>内蒙古</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241213/2293349941.html\"></a></td>\n   </tr>\n   <tr>\n    <td>辽宁</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241212/2293348581.html\">辽宁：2025年全国硕士研究生招生考试准考证打印温馨提示</a></td>\n   </tr>\n   <tr>\n    <td>吉林</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241211/2293348545.html\">吉林：致全省2025年研考考生的一封信</a><br><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241211/2293348544.html\">吉林省2025年全国硕士研究生招生考试违规举报受理电话</a></td>\n   </tr>\n   <tr>\n    <td>黑龙江</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241210/2293348426.html\">黑龙江省2025年全国硕士研究生招生考试（初试）考前温馨提示</a></td>\n   </tr>\n   <tr>\n    <td>上海</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241211/2293348515.html\">2025年上海市硕士研究生招生考试（初试）考前提醒</a></td>\n   </tr>\n   <tr>\n    <td>江苏</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241213/2293349941.html\"></a></td>\n   </tr>\n   <tr>\n    <td>浙江</td>\n    <td><a target=\"_blank\" rel=\"nofollow\" href=\"https://yz.chsi.com.cn/kyzx/kydt/202412/20241212/2293348568.html\">浙江：2025年硕士研究生招生考试文具和计算器使用说明</a></td>\n   </tr>\n   <tr>\n    <td>安徽</td>\n    <td><a target=\"_blank\" rel=\"nof