INSERT INTO `yl_guide` VALUES (55, '浙江音乐学院2025年硕士研究生招生调剂复试工作通知(二)', '<h1>浙江音乐学院2025年硕士研究生招生调剂复试工作通知(二)</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：浙江音乐学院 2025-11-18　 相关院校：<a href=\"/graduate/grad/schoolID/3073.shtml\" title=\"浙江音乐学院研究生院\" target=\"_blank\"><b>浙江音乐学院</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/3073.shtml\" target=\"_blank\" title=\"浙江音乐学院考研资料\"><font color=\"#ff0000\">浙江音乐学院2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>根据教育部及我校相关文件精神，经研究生招生工作领导小组审议，结合我校调剂名额计划及实际各研究方向报名情况，拟定参加调剂复试考生名单。具体名单详见附件。</p>\n <p>我校已通过中国研究生招生信息网后台向考生发送复试通知，请接到通知的考生按照我校4月8日公布的《浙江音乐学院2025年硕士研究生招生调剂复试工作通知(一)》的要求准备及参加调剂复试。</p>\n <p>研究生处招生联系电话：0571-89808075，89808076(工作日8:00-11:30、13:30&#x2014;16:30)</p>\n <p>联系邮箱：yjszs@zjcm.edu.cn</p>\n <p>祝各位考试顺利!</p>\n <p><a rel=\"nofollow\" target=\"_blank\" href=\"https://www.zjcm.edu.cn/attachment/20250409/dd9e7e73938b26211591392121a6ec2c.pdf?n=2025%E5%B9%B4%E8%B0%83%E5%89%82%E5%A4%8D%E8%AF%95%E5%90%8D%E5%8D%95\"><font color=\"#008080\">附件：浙江音乐学院2025年调剂复试名单.pdf</font></a></p>\n</div>', 'fushixize', NULL, 0, 1, '2025-12-12 15:07:35', NULL, 0, '浙江音乐学院', '不限', 0);
INSERT INTO `yl_guide` VALUES (56, '浙江音乐学院2025年硕士研究生招生调剂复试工作通知(一)', '<h1>浙江音乐学院2025年硕士研究生招生调剂复试工作通知(一)</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：浙江音乐学院 2025-11-18　 相关院校：<a href=\"/graduate/grad/schoolID/3073.shtml\" title=\"浙江音乐学院研究生院\" target=\"_blank\"><b>浙江音乐学院</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/3073.shtml\" target=\"_blank\" title=\"浙江音乐学院考研资料\"><font color=\"#ff0000\">浙江音乐学院2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>我校调剂复试工作根据《2025年全国硕士研究生招生工作管理规定》《浙江音乐学院关于开展2025年硕士研究生招生调剂工作的通知》等文件精神执行，相关工作通知如下：</p>\n <p><strong>一、复试时间及地点</strong></p>\n <p>1.复试时间：4月10日。</p>\n <p>2.复试地点：浙江音乐学院。</p>\n <p><strong>二、复试日程</strong></p>\n <p></p>\n <table border=\"1\" cellspacing=\"0\" cellpadding=\"0\" width=\"98%\">\n  <tbody>\n   <tr>\n    <td width=\"89\">\n     <div align=\"center\">\n      日期\n     </div></td>\n    <td width=\"120\">\n     <div align=\"center\">\n      时间\n     </div></td>\n    <td width=\"251\">\n     <div align=\"center\">\n      考试科目\n     </div></td>\n    <td width=\"253\">\n     <div align=\"center\">\n      地点\n     </div></td>\n   </tr>\n   <tr>\n    <td rowspan=\"3\" width=\"89\">\n     <div align=\"center\">\n      4月10日\n     </div>\n     <div align=\"center\">\n      （周四）\n     </div></td>\n    <td width=\"120\">\n     <div align=\"center\">\n      上午8:30-11:30\n     </div></td>\n    <td width=\"251\">\n     <div align=\"center\">\n      专业笔试\n     </div></td>\n    <td width=\"253\">\n     <div align=\"center\">\n      音工楼15A-110\n     </div></td>\n   </tr>\n   <tr>\n    <td width=\"120\">\n     <div align=\"center\">\n      下午1:00-\n     </div></td>\n    <td width=\"251\">\n     <div align=\"center\">\n      英语口语及听力测试、\n     </div>\n     <div align=\"center\">\n      专业面试\n     </div></td>\n    <td width=\"253\">\n     <div align=\"center\">\n      综合教学楼15B，检录批次及具体考场详见复试准考证。\n     </div></td>\n   </tr>\n   <tr>\n    <td width=\"120\">\n     <div align=\"center\">\n      8:00-20:00\n     </div></td>\n    <td width=\"251\">\n     <div align=\"center\">\n      心理测试\n     </div></td>\n    <td width=\"253\">\n     <div align=\"center\">\n      线上心理测试\n     </div></td>\n   </tr>\n  </tbody>\n </table>\n <p></p>\n <p><strong>三、所有参加复试的考生</strong>都必须登陆系统进行信息填报与资料上传，系统开放时间为4月9日9:30-13:30，具体操作流程详见附件1。</p>\n <p>请各位考生根据系统要求填报和上传相关材料，学校在复试前对考生提交的报名材料原件及考生资格进行严格审查，对不符合规定者，不予复试。</p>\n <p>请各位考生登录信息填报系统打印复试准考证，准考证打印开通时间为4月9日18:00。</p>\n <p><strong>四、所有参加复试的考生都必须进行心理测试，系统开放时间为4月10日8:00-20:00，操作方法详见附件2。</strong></p>\n <p><strong>五、其他</strong></p>\n <p>(一)复试提交材料</p>\n <p>1.《浙江音乐学院研究生招生政治思想品德考查表》;</p>\n <p>2.身份证(正、反两面);</p>\n <p>3.学历、学位证书(应届本科毕业生无须提交)、教育部学籍在线验证报告(应届生)、教育部学历证书电子注册备案表或中国高等教育学位在线验证报告(往届生);在国外获得学位的考生，应提供由教育部留学服务中心出具的学历证明;</p>\n <p>4.应届本科毕业生须提交注册完整的学生证，如学生证注册不完整需提供由考生学籍管理部门出具的在读证明;</p>\n <p>5.同等学力考生须提交进修本科课程成绩单、报考专业领域的两位副高以上职称的专家推荐信;</p>\n <p>6.“退役大学生士兵”专项计划考生须提交《入伍批准书》和《退出现役证》;</p>\n <p>7.立功表彰退役军人免试生须提交《入伍批准书》《退出现役证》和立功表彰证明;</p>\n <p>8.其他专项计划加分考生须提交相关计划服务期满、考核合格的证件。</p>\n <p>(二)其他相关事项</p>\n <p>1.全体考生务必携带本人身份证原件、复试准考证原件、《浙江音乐学院研究生招生政治思想品德考查表》原件准时到达检录处进行检录，超过规定时间15分钟的迟到考生均不允许进入各考场，请根据考试时间提前30分钟候考。考生自备钢琴伴奏或其他乐器伴奏的，伴奏人员需携带身份证原件，与考生同时进场检录，检录要求与考生一致，迟到15分钟不允许进入考场。</p>\n <p>2.有要求提交论文、作品等的研究方向，考生都需隐去自己的姓名、准考证号等相关信息，打印并携带一式8份纸质稿在考试时提交。如果发现一律根据相关政策做出取消违规科目考试成绩等相应处理。</p>\n <p>3.严禁携带各种通讯工具(如手机、电子手表等具有发送或接收信息功能的设备)、电子存储记忆录放设备(如iPad)等物品进入考场。如果发现一律根据相关政策做出取消考试资格等相应处理。</p>\n <p>4.根据《浙江音乐学院硕士研究生招生专业考试考场规则》规定：考试过程中，听从评分教师的指令进行考试，不得询问涉及试题内容的问题，不得暗示或说出自己的姓名、准考证号等。违规者根据相关政策做出取消违规科目考试成绩等相应处理。</p>\n <p>5.我校研究生复试不收取考生任何费用，如有冒充学院工作人员或研究生导师，以各种方式让考生交费，请及时与我校研招办联系核实。</p>\n <p>6.我校从未委托任何机构或个人办理调剂事宜，招生信息以我校网站发布的为准。</p>\n <p>7.复试至录取通知书发放期间，务必保持手机联系畅通。</p>\n <p>8.联系方式：</p>\n <p>招生电话：0571-89808075，89808076</p>\n <p>(工作日：8:00-11:30，13:30&#x2014;16:30)</p>\n <p>邮箱：yjszs@zjcm.edu.cn</p>\n <p>祝各位考生考试顺利!</p>\n <p>附件1：浙江音乐学院2025研究生信息采集系统-操作手册.pdf</p>\n <p>附件2：浙江音乐学院关于2025年硕士研究生复试心理测试的通知.pdf</p>\n <p>附件https://www.zjcm.edu.cn/zyxww/tzgg/202504/44972.html</p>\n</div>', 'fushixize', NULL, 0, 1, '2025-12-12 15:07:36', NULL, 0, '浙江音乐学院', '不限', 0);
INSERT INTO `yl_guide` VALUES (57, '浙江音乐学院2025年硕士研究生招生复试相关工作通知(三)', '<h1>浙江音乐学院2025年硕士研究生招生复试相关工作通知(三)</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：浙江音乐学院 2025-11-18　 相关院校：<a href=\"/graduate/grad/schoolID/3073.shtml\" title=\"浙江音乐学院研究生院\" target=\"_blank\"><b>浙江音乐学院</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/3073.shtml\" target=\"_blank\" title=\"浙江音乐学院考研资料\"><font color=\"#ff0000\">浙江音乐学院2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p><strong>一、复试日程</strong></p>\n <p></p>\n <table border=\"1\" width=\"98%\">\n  <tbody>\n   <tr>\n    <td valign=\"middle\" width=\"102\">\n     <div align=\"center\">\n      日期\n     </div></td>\n    <td valign=\"middle\" width=\"126\">\n     <div align=\"center\">\n      时间\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      考试科目\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div align=\"center\">\n      考试地点\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" width=\"228\" colspan=\"2\">\n     <div align=\"center\">\n      3月27日（周四）9:00-\n     </div>\n     <div align=\"center\">\n      3月28日（周五）12:00\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      心理测试\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div align=\"center\">\n      线上心理测试\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" rowspan=\"4\" width=\"102\">\n     <div align=\"center\">\n      3月28日\n     </div>\n     <div align=\"center\">\n      （周五）\n     </div></td>\n    <td valign=\"middle\" width=\"126\">\n     <div align=\"center\">\n      8:15开始\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      考生检录\n     </div></td>\n    <td valign=\"middle\" rowspan=\"3\" width=\"198\">\n     <div align=\"center\">\n      综合教学楼15B\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" width=\"126\">\n     <div align=\"center\">\n      8:30-\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      英语口语及听力测试\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" width=\"126\">\n     <div align=\"center\">\n      2:00-5:00\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      笔试科目考试\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" width=\"126\">\n     <div align=\"center\">\n      2:00-5:00\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      音乐工程系上机操作\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div>\n      综合教学楼15A\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" rowspan=\"3\" width=\"102\">\n     <div align=\"center\">\n      3月29日\n     </div>\n     <div align=\"center\">\n      （周六）\n     </div></td>\n    <td valign=\"middle\" width=\"126\">\n     <div align=\"center\">\n      8:00开始\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      考生检录\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div>\n      舞蹈楼、附中楼大厅\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" rowspan=\"2\" width=\"126\">\n     <div align=\"center\">\n      8:30-\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      作曲与指挥系、音乐学系、\n     </div>\n     <div align=\"center\">\n      声乐歌剧系、流行音乐系、\n     </div>\n     <div align=\"center\">\n      舞蹈学院、音乐工程系各方向\n     </div>\n     <div align=\"center\">\n      专业主课及专业面试\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div>\n      舞蹈楼各考场\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      音乐教育学院、钢琴系、艺术与文化管理高等研究院各方向\n     </div>\n     <div>\n      专业主课及专业面试\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div>\n      附中楼各考场\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" rowspan=\"3\" width=\"102\">\n     <div align=\"center\">\n      3月30日\n     </div>\n     <div align=\"center\">\n      （周日）\n     </div></td>\n    <td valign=\"middle\" width=\"126\">\n     <div align=\"center\">\n      8:00开始\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      考生检录\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div>\n      舞蹈楼、附中楼大厅\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" rowspan=\"2\" width=\"126\">\n     <div align=\"center\">\n      8:30-\n     </div></td>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      国乐系、管弦系、音乐工程系各方向专业主课及专业面试\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div>\n      舞蹈楼各考场\n     </div></td>\n   </tr>\n   <tr>\n    <td valign=\"middle\" width=\"267\">\n     <div align=\"center\">\n      音乐教育学院（音乐教育合作办学方向）专业主课及专业面试\n     </div></td>\n    <td valign=\"middle\" width=\"198\">\n     <div>\n      附中楼各考场\n     </div></td>\n   </tr>\n  </tbody>\n </table>\n <p></p>\n <p>备注：检录批次及具体考场详见复试准考证。</p>\n <p><strong>二、其他</strong></p>\n <p>1.请各位考生登录信息填报系统打印复试准考证，准考证打印开通时间为3月27日10:00。</p>\n <p>2.全体考生务必携带本人身份证原件、复试准考证打印纸质版、《浙江音乐学院研究生招生政治思想品德考查表》原件准时到达检录处进行检录，超过规定时间15分钟的迟到考生均不允许进入各考场，请根据考试时间提前30分钟候考。</p>\n <p>考生自备钢琴伴奏或其他乐器伴奏的，伴奏人员需携带身份证原件，与考生同时进场检录，检录要求与考生一致，迟到15分钟不允许进入考场。</p>\n <p><strong>三、研究生处招生联系电话：</strong></p>\n <p>0571-89808076，89808075(工作日8:00-11:30、13:30&#x2014;16:30)</p>\n <p>联系邮箱：yjszs@zjcm.edu.cn</p>\n <p>祝各位考生考试顺利!</p>\n</div>', 'fushixize', NULL, 0, 1, '2025-12-12 15:07:37', NULL, 0, '浙江音乐学院', '不限', 0);
INSERT INTO `yl_guide` VALUES (58, '浙江音乐学院2025年硕士研究生招生复试相关工作通知(二)', '<h1>浙江音乐学院2025年硕士研究生招生复试相关工作通知(二)</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：浙江音乐学院 2025-11-18　 相关院校：<a href=\"/graduate/grad/schoolID/3073.shtml\" title=\"浙江音乐学院研究生院\" target=\"_blank\"><b>浙江音乐学院</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/3073.shtml\" target=\"_blank\" title=\"浙江音乐学院考研资料\"><font color=\"#ff0000\">浙江音乐学院2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>各位考生：</p>\n <p>根据教育部及教育厅相关文件会议精神，结合学校研究生招生工作领导小组总体安排，现将复试相关工作通知如下：</p>\n <p><strong>一、所有参加复试的考生</strong>都必须登陆系统进行信息填报与资料上传，系统关闭时间为3月26日12:00，具体操作流程详见附件1。</p>\n <p>请各位考生根据系统要求填报和上传相关材料，学校在复试前对考生提交的报名材料原件及考生资格进行严格审查，对不符合规定者，不予复试。</p>\n <p><strong>二、所有参加复试的考生</strong>都必须进行心理测试，系统开放时间为3月27日9:00-3月28日12:00，操作方法详见附件2。</p>\n <p><strong>三、其他</strong></p>\n <p>1.全体考生务必携带本人身份证原件、复试准考证原件、《浙江音乐学院研究生招生政治思想品德考查表》原件准时到达检录处进行检录，超过规定时间15分钟的迟到考生均不允许进入各考场，请根据考试时间提前30分钟候考。</p>\n <p>考生自备钢琴伴奏或其他乐器伴奏的，伴奏人员需携带身份证原件，与考生同时进场检录，检录要求与考生一致，迟到15分钟不允许进入考场。</p>\n <p>音乐教育方向器乐主项不得使用任何伴奏。</p>\n <p>2.所有考生须登录系统填报完善个人相关信息，复试准考证请登录信息填报系统进行打印，可在考试前一天通过系统导出打印。</p>\n <p>3.材料准备注意事项</p>\n <p>(1)请在系统注册时登记考试曲目。</p>\n <p>(2)有要求提交论文、作品等的研究方向，考生都需隐去自己的姓名、准考证号等相关信息，打印并携带一式8份纸质稿在检录时提交给检录处。</p>\n <p>(3)根据招生简章规定，需携带伴奏音频、制作音乐工程文件等的，需隐去自己的姓名、准考证号等相关信息，将音频内容保存至U盘或光盘，在检录时将U盘或光盘提交给检录处。</p>\n <p>(4)舞蹈教育方向考生说课展示部分，请自选一个授课主题并制作PPT，需隐去自己的姓名、准考证号等相关信息，将PPT存入U盘，在检录时将U盘提交给检录处。</p>\n <p>(5)音乐工程系考生在英语口语与听力测试结束后，请前往综合教学楼15A-433上机操作考场调试设备，熟悉考试环境;设备调试截止时间为13:00。</p>\n <p>正式考试开始前半个小时允许考生入场再次调试设备与软件。</p>\n <p>见原文</p>\n <p>4.严禁携带各种通讯工具(如手机、电子手表等具有发送或接收信息功能的设备)、电子存储记忆录放设备(如iPad)等物品进入考场。如果发现一律根据相关政策做出取消考试资格等相应处理。</p>\n <p>5.根据《浙江音乐学院硕士研究生招生专业考试考场规则》规定：考试过程中，听从评分教师的指令进行考试，不得询问涉及试题内容的问题，不得暗示或说出自己的姓名、准考证号等。</p>\n <p>6.诚信复试。所有考生需签署《浙江音乐学院2025年硕士研究生招生考试诚信承诺书》。研究生招生考试是国家教育考试，复试工作是研究生招生考试的重要组成部分。考生要确保所有提交材料真实，诚信守规参加复试。须知晓：在法律规定的国家考试中，组织作弊的行为;为他人实施组织作弊提供作弊器材或者其他帮助的行为;为实施考试作弊行为，向他人非法出售或者提供考试的试题、答案的行为;代替他人或者让他人代替自己参加考试的行为都将触犯刑法。在复试过程中有违规行为的考生，一经查实，即按照规定严肃处理，取消录取资格，记入《考生考试诚信档案》。入学后3个月内，我校将按照《普通高等学校学生管理规定》有关要求，对所有考生进行全面复查。复查不合格的，取消学籍;情节严重的，移交有关部门调查处理。</p>\n <p>7.如需自驾车辆进入考点，请凭复试准考证进入，听从指挥，将车辆停放地下车库，临时接送车辆即停即走;学校周边交通路况复杂，请考生及时了解杭州市区相关交通规定，选择合适的交通工具提前出行，以免误考。考试当天6:30后考生、家长方可进入校园。</p>\n <p>在综艺楼(附中楼)参加考试的考生，建议从浙音路东1门(行车道)或东大门(人行道)进入校园;在南区综合教学楼15B参加考试的考生，请从东南门进入校园。如乘坐地铁6号线到浙江音乐学院站，可从C口出站至知音路“浙江音乐学院东南门”进入校园。</p>\n <p>8.根据我校研究生招生考试工作部署，每位考生可有1-2名家长陪同进入校园。考生及家长进校时，需携带有效身份证件，配合校园安保核验。</p>\n <p>9.建议出行和进入校园内(除考试外)佩戴口罩，加强个人防护，做自己健康的第一责任人。</p>\n <p>10.学校提供琴房给当天考试的考生进行考前练习(琴房开放时间为3月29日6：30&#x2014;20：30，3月30日6:30-16:30)，请考生注意练习时间，切勿错过考试。</p>\n <p>11.学校南区餐厅、北区餐厅向考生与家长开放，可到餐厅购买餐券用餐和休息。</p>\n <p>四、研究生处招生联系电话：</p>\n <p>0571-89808076，89808075(工作日8:00-11:30、13:30&#x2014;16:30)</p>\n <p>联系邮箱：yjszs@zjcm.edu.cn</p>\n <p>祝各位考生考试顺利!</p>\n <p>附件1：浙江音乐学院2025研究生信息采集系统-操作手册.pdf</p>\n <p>附件2：浙江音乐学院关于2025年硕士研究生复试心理测试的通知.pdf</p>\n <p>附件3：浙江音乐学院2025年硕士研究生招生考试复试及录取工作方案.pdf</p>\n <p>附件4：浙江音乐学院2025年硕士研究生招生复试名单.pdf</p>\n <p>附件5：浙江音乐学院2025年硕士研究生招生复试名额拟分配计划表.pdf</p>\n <p>原文链接https://www.zjcm.edu.cn/zyxww/tzgg/202503/44467.html</p>\n</div>', 'fushixize', NULL, 0, 1, '2025-12-12 15:07:37', NULL, 0, '浙江音乐学院', '不限', 0);
INSERT INTO `yl_guide` VALUES (59, '浙江音乐学院2025年硕士研究生招生复试相关工作通知(一)', '<h1>浙江音乐学院2025年硕士研究生招生复试相关工作通知(一)</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：浙江音乐学院 2025-11-18　 相关院校：<a href=\"/graduate/grad/schoolID/3073.shtml\" title=\"浙江音乐学院研究生院\" target=\"_blank\"><b>浙江音乐学院</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/3073.shtml\" target=\"_blank\" title=\"浙江音乐学院考研资料\"><font color=\"#ff0000\">浙江音乐学院2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>根据《2025年全国硕士研究生招生工作管理规定》及教育部、省教育考试院相关文件精神，2025年我校硕士研究生招生录取工作贯彻“按需招生、全面衡量、择优录取、宁缺毋滥”的原则，在确保安全性、公平性和科学性的基础上，统筹做好复试录取工作，现将有关工作通知如下：</p>\n <p><strong>一、复试分数线</strong>见<a rel=\"nofollow\" target=\"_blank\" href=\"https://www.zjcm.edu.cn/zyxww/tzgg/202503/44432.html\">https://www.zjcm.edu.cn/zyxww/tzgg/202503/44432.html</a></p>\n <p>二<strong>、复试时间及地点</strong></p>\n <p>1.复试时间：2025年3月28日-30日，具体日程安排详见后续发布的相关通知。</p>\n <p>2.复试地点：浙江省杭州市西湖区转塘街道浙音路1号浙江音乐学院。</p>\n <p><strong>三、复试审查内容</strong></p>\n <p>学校在复试前对考生的居民身份证、学历学位证书、学历学籍核验结果、思想政治品德审查表等报名材料原件及考生资格进行严格审查，对不符合规定者，不予复试。</p>\n <p>(一)对考生资格的审查</p>\n <p>考生请准备好以下材料原件电子版(图片文件)，根据后续通知登录系统提交，我校将对考生资格进行审查：</p>\n <p>1.《浙江音乐学院研究生招生政治思想品德考查表》;</p>\n <p>2.身份证(正、反两面);</p>\n <p>3.学历、学位证书(应届本科毕业生无须提交)、教育部学籍在线验证报告(应届生)、教育部学历证书电子注册备案表或中国高等教育学位在线验证报告(往届生);在国外获得学位的考生，应提供由教育部留学服务中心出具的学历证明;</p>\n <p>4.应届本科毕业生须提交注册完整的学生证，如学生证注册不完整需提供由考生学籍管理部门出具的在读证明;</p>\n <p>5.同等学力考生须提交进修本科课程成绩单、报考专业领域的两位副高以上职称的专家推荐信;</p>\n <p>6.“退役大学生士兵”专项计划考生须提交《入伍批准书》和《退出现役证》;</p>\n <p>7.立功表彰退役军人免试生须提交《入伍批准书》《退出现役证》和立功表彰证明;</p>\n <p>8.其他专项计划加分考生须提交相关计划服务期满、考核合格的证件。</p>\n <p>(二)对考生政治思想品德的考核</p>\n <p>对复试考生进行政治思想品德考核是保证入学新生政治素质的重要环节。所有考生均须填写《浙江音乐学院研究生招生政治思想品德考查表》，由档案所在地负责填写相关内容并盖章。拟录取名单确定后，研究生处向考生所在单位函调人事档案和本人现实表现等材料，全面审查其政治情况。</p>\n <p>(三)定向就业的考生应当在被录取前与我校、用人单位分别签订定向就业合同。报考非定向就业研究生录取为定向就业的，我校将严格审核定向就业合同，从严掌握。</p>\n <p>考生因报考硕士研究生与所在单位产生的问题由考生自行处理。若因此造成考生不能复试或无法录取，我校不承担责任。</p>\n <p><strong>四、重要提醒</strong></p>\n <p>1.因教育部指标尚未正式下达，复试名单、招生计划及其他相关内容将于后续发布，请持续关注我校官网相关通知。</p>\n <p>2.音乐教育方向器乐主项不得使用任何伴奏。</p>\n <p>3.所有考生须登录系统填报完善个人相关信息，系统填报时间及操作办法请关注官网后续通知。</p>\n <p>4.符合国家加分政策的考生请在3月26日17:00前向学校提出文字申请(手写签名)并提交相关证明材料，将证明材料原件图片发送至邮箱yjszs@zjcm.edu.cn，邮件标题须注明：申请加分项名称+姓名+报考研究方向+准考证号码。</p>\n <p>5.我校研究生复试不收取考生任何费用，如有冒充学校工作人员或研究生导师，以各种方式让考生交费，请及时与我校研招办联系核实。</p>\n <p>6.复试至录取通知书发放期间，请务必保持手机联系畅通。</p>\n <p>7.招生工作期间的政策和规定按照国家有关部门及教育部最新文件执行。如遇上级部门政策调整，学校将做相应调整，并及时在学校官方网站予以公布。</p>\n <p><strong>五、咨询方式</strong></p>\n <p>1.研究生处招生联系电话：</p>\n <p>0571-89808076、89808075(工作日8:00-11:30、13:30&#x2014;16:30)</p>\n <p>联系邮箱：yjszs@zjcm.edu.cn</p>\n <p>2.我校举报信箱：jbx@zjcm.edu.cn，</p>\n <p>举报电话：0571-89808200，接受社会监督。</p>\n <p>祝各位考生考试顺利!</p>\n</div>', 'fushixize', NULL, 0, 1, '2025-12-12 15:07:38', NULL, 0, '浙江音乐学院', '不限', 0);
INSERT INTO `yl_guide` VALUES (60, '浙江音乐学院关于2025年硕士研究生招生复试相关工作提示', '<h1>浙江音乐学院关于2025年硕士研究生招生复试相关工作提示</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：浙江音乐学院 2025-11-18　 相关院校：<a href=\"/graduate/grad/schoolID/3073.shtml\" title=\"浙江音乐学院研究生院\" target=\"_blank\"><b>浙江音乐学院</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/3073.shtml\" target=\"_blank\" title=\"浙江音乐学院考研资料\"><font color=\"#ff0000\">浙江音乐学院2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p>各位考生：</p>\n <p>欢迎报考浙江音乐学院!近日，教育部已公布国家分数线，为方便考生更好地了解我校硕士研究生复试录取工作的安排，现将相关情况提示如下：</p>\n <p><strong>一、复试时间</strong></p>\n <p>按照教育部要求，我校2025年硕士研究生复试工作将于3月下旬正式启动，具体时间请关注学校官网相关通知公告。</p>\n <p>由于教育部招生计划尚未下达，因此各专业实际招生人数未完全确定。待正式下达后，我校将根据教育部及浙江省教育考试院相关文件精神发布复试相关信息，请各位考生耐心等待我校公告。</p>\n <p><strong>二、复试形式</strong></p>\n <p>我校硕士研究生复试采用线下复试的方式进行，请考生密切关注后续通知以及相关规定。</p>\n <p><strong>三、复试内容</strong></p>\n <p>复试共有专业主课、专业面试、英语口语及听力测试、思想政治素质和品德考核、心理测试五个部分。复试内容可参考《浙江音乐学院2025年硕士研究生招生简章》具体要求。</p>\n <p><strong>四、复试资格审查</strong></p>\n <p>为严格复试资格审查，考生可提前准备好以下材料原件及电子版(图片或扫描PDF)：</p>\n <p>1.考生身份证(正反两面);</p>\n <p>2.考生初试准考证;</p>\n <p>3.应届考生注册完整(含最后一学期)的学生证，如学生证注册不完整需提供由考生学籍管理部门出具的在读证明原件;</p>\n <p>4.往届考生学历学位证书原件;</p>\n <p>5.学籍学历认证报告电子版(应届生提供《教育部学籍在线验证报告》，往届生提供《教育部学历证书电子注册备案表》)，查询网址为：https://www.chsi.com.cn/xlcx/bgcx.jsp。国(境)外获得学历学位的考生须提供教育部留学服务中心出具的《国(境)外学历学位认证书》;</p>\n <p>6.《浙江音乐学院研究生招生政治思想品德考查表》。</p>\n <p>7.除以上材料外，退役大学生士兵计划考生需提供《入伍批准书》和《退出现役证》;同等学力考生需提供进修本科课程成绩单原件、报考专业领域的两位副高以上职称的专家推荐信。</p>\n <p><strong>五、重要提醒</strong></p>\n <p>1.官方信息发布渠道</p>\n <p>我校所有招生信息均通过以下官方渠道发布：</p>\n <p>教育部指定平台：中国研究生招生信息网(https://yz.chsi.com.cn/);</p>\n <p>浙江音乐学院官方平台：</p>\n <p>浙江音乐学院官网(https://www.zjcm.edu.cn/);</p>\n <p>“浙江音乐学院”“浙江音乐学院研究生教育”微信公众号。</p>\n <p>2.调剂信息发布</p>\n <p>一志愿考生复试录取工作结束后，如需进行调剂相关工作，调剂信息将统一通过教育部指定平台&#x2014;&#x2014;“全国硕士生招生复试调剂服务系统”、浙江音乐学院官网及官方微信公众号发布。</p>\n <p>3.诚信复试</p>\n <p>研究生招生考试是国家教育考试，复试工作是研究生招生考试的重要组成部分。考生要确保所有提交材料真实，诚信守规参加复试。须知晓：在法律规定的国家考试中，组织作弊的行为;为他人实施组织作弊提供作弊器材或者其他帮助的行为;为实施考试作弊行为，向他人非法出售或者提供考试的试题、答案的行为;代替他人或者让他人代替自己参加考试的行为都将触犯刑法。在复试过程中有违规行为的考生，一经查实，即按照规定严肃处理，取消录取资格，记入《考生考试诚信档案》。入学后3个月内，我校将按照《普通高等学校学生管理规定》有关要求，对所有考生进行全面复查。复查不合格的，取消学籍;情节严重的，移交有关部门调查处理。</p>\n <p>4.复试内容属于国家机密级。在我校硕士研究生招生工作结束前，严禁将考试相关信息泄露或对外公布。</p>\n <p>复试过程中，考生应严格遵守复试纪律，不以任何形式作弊。</p>\n <p>5.谨防诈骗。</p>\n <p>我校研究生复试不收取任何费用，除以上官方信息发布渠道，我校未委托任何单位、个人和平台发布我校研究生招生复试及调剂信息。如有冒充学校工作人员或研究生导师，以各种方式让考生交费，请及时与我校研招办联系核实。</p>\n <p>对于任何假冒我校名义进行招生活动的机构和个人，我校将坚决依法追究其法律责任。请广大考生仔细甄别网络上的研究生招生信息，谨防上当受骗或财物受损，一切招生信息以教育主管部门及我校官方发布信息为准。</p>\n <p><strong>六、联系方式</strong></p>\n <p>研招办联系电话：0571-89808076 89808075(工作日，8:00-11:30，13:30&#x2014;16:30)</p>\n <p>邮箱：yjszs@zjcm.edu.cn</p>\n <p><a rel=\"nofollow\" target=\"_blank\" href=\"https://www.zjcm.edu.cn/attachment/20240315/7a01195da6838ad228bcb776f5f90731.docx?n=%E9%99%84%E4%BB%B6%EF%BC%9A%E6%B5%99%E6%B1%9F%E9%9F%B3%E4%B9%90%E5%AD%A6%E9%99%A2%E7%A0%94%E7%A9%B6%E7%94%9F%E6%8B%9B%E7%94%9F%E6%94%BF%E6%B2%BB%E6%80%9D%E6%83%B3%E5%93%81%E5%BE%B7%E8%80%83%E6%9F%A5%E8%A1%A8\"><font color=\"#008080\">附件：浙江音乐学院研究生招生政治思想品德考查表.docx</font></a></p>\n <p>浙江音乐学院研究生处</p>\n <p>2025年3月7日</p>\n</div>', 'fushixize', NULL, 0, 1, '2025-12-12 15:07:39', NULL, 0, '浙江音乐学院', '不限', 0);
INSERT INTO `yl_guide` VALUES (61, '华侨大学2026年硕士招生专业复试相关内容一览', '<h1>华侨大学2026年硕士招生专业复试相关内容一览</h1>\n<div class=\"time\" style=\"margin-top:5px;margin-bottom:10px;\">\n <a href=\"/info/list/ClassID/23.shtml\" target=\"_blank\" title=\"更多考研复试相关内容列表\">考研复试</a> 来源：华侨大学研究生招生信息网 2025-11-10　 相关院校：<a href=\"/graduate/grad/schoolID/680.shtml\" title=\"华侨大学研究生院\" target=\"_blank\"><b>华侨大学</b></a>\n</div>\n<div style=\"margin-top:10px;margin-bottom:0px;\">\n <div class=\"_4ezfie18m8i\"></div>\n</div>\n<div class=\"cont\" style=\"margin-top:5px;\">\n <ul>\n  <li><a rel=\"nofollow\" href=\"https://dl.koolearn.com/sXmT92X\" target=\"_blank\"><font color=\"#ff0000\">2026考研英语全程班 6班 </font></a></li>\n  <li><a rel=\"nofollow\" href=\"https://tgc.orangevip.com/releasehtml/index756.html?jt_site_id=32431&amp;source=0\" target=\"_blank\"><font color=\"#ff0000\">26考研全科上岸规划营「择校&#x25aa;规划&#x25aa;备考」</font></a></li>\n  <li><a href=\"/note/SchoolShow/id/680.shtml\" target=\"_blank\" title=\"华侨大学考研资料\"><font color=\"#ff0000\">华侨大学2026考研专业课复习资料「真题&#x25aa;笔记&#x25aa;讲义&#x25aa;题库」</font></a></li>\n </ul>\n</div>\n<div class=\"hr20\"></div>\n<div>\n <a target=\"_blank\" rel=\"nofollow\" href=\"https://mp.weixin.qq.com/s/S3jtisbmi-ZA0YDLDZKJCg\"><img src=\"https://download.chinakaoyan.com/wwwfile/2025/ke/20250808171711.png\"></a>\n</div>\n<div class=\"cont\" style=\"margin-top:-5px;margin-bottom:5px;\">\n 　\n <p><strong>(10月15日更新)华侨大学2026年硕士招生专业复试相关内容一览(仅供参考)</strong></p>\n <p>华侨大学2026年硕士招生专业复试相关内容见附件，附件中相关内容仅供参考，复试具体事宜届时以学校复试录取工作方案及各学院实施细则(一般在每年3月中下旬发布)为准。</p>\n <p>附件【<a rel=\"nofollow\" target=\"_blank\" href=\"https://yjszs.hqu.edu.cn/system/_content/download.jsp?urltype=news.DownloadAttachUrl&amp;owner=1309592104&amp;wbfileid=435F1911E0CA31589FFDD01F1AF40405\"><font color=\"#008080\">（10月15日更新）华侨大学2026年硕士招生专业复试内容一览表（仅供参考）.xlsx</font></a>】</p>\n</div>', 'fushixize', NULL, 1, 1, '2025-12-12 15:07:39', NULL, 0, '华侨大学', '不限', 0);
